/**
 * Extension du pool ACITP — 135 questions supplémentaires
 * Domaines: macos(35), abm(30), security(25), deployment(20), network(15), productivity(5), troubleshooting(5)
 * Porte le total à ~200 questions uniques pour un vrai tirage aléatoire
 */
import type { Question } from "@/lib/types";
import { buildQuestion } from "@/lib/quiz/question-builder";
import type { AcitpExamDomain } from "@/lib/data/acitp/domains";

type QInput = {
  id: string;
  domain: AcitpExamDomain;
  text: string;
  correct: string;
  distractors: [string, string, string];
  explanation: string;
};

function q(input: QInput): Question {
  return buildQuestion({
    id: input.id,
    text: input.text,
    correct: input.correct,
    distractors: input.distractors,
    explanation: input.explanation,
    moduleLabel: input.domain,
  });
}

